module regfile (
	input clk,
	input reset,
	input [1:0] write_addr,
	input [15:0] write_data,
	input write_en,
	input [1:0] read_addr,
	output reg [15:0] read_data
);reg [15:0] registers [3:0];

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset) begin
		registers[0] <= 16'b0;
		registers[1] <= 16'b0;
		registers[2] <= 16'b0;
		registers[3] <= 16'b0;
	end else if (write_en) begin
		registers[write_addr] <= write_data;
	end
end

always @(*) begin
	read_data = registers[read_addr];
end

endmodule
